SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS=0;


-- ----------------------------
-- Table structure for `auth_activity_logs`
-- ----------------------------
DROP TABLE IF EXISTS `auth_activity_logs`;
CREATE TABLE `auth_activity_logs` (
  `id` varchar(36) NOT NULL COMMENT 'UUID',
  `code` int(11) NOT NULL AUTO_INCREMENT COMMENT '순번 (AUTO_INCREMENT)',
  `user_id` varchar(36) NOT NULL COMMENT 'auth_users.id 참조',
  `action` varchar(255) NOT NULL COMMENT '수행한 작업 (예: login, update_profile, delete_user)',
  `target` varchar(255) DEFAULT NULL COMMENT '대상 데이터 또는 페이지 경로',
  `ip_address` varchar(45) DEFAULT NULL COMMENT '접속 IP',
  `user_agent` varchar(255) DEFAULT NULL COMMENT '브라우저/기기 정보',
  `description` text COMMENT '추가 상세 설명 (선택)',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '로그 발생 시각',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_code` (`code`) USING BTREE,
  KEY `idx_user_id` (`user_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='사용자 활동 로그 테이블 (UUID + 순번 구조)';


-- ----------------------------
-- Table structure for `auth_permissions`
-- ----------------------------
DROP TABLE IF EXISTS `auth_permissions`;
CREATE TABLE `auth_permissions` (
  `id` varchar(36) NOT NULL COMMENT 'UUID',
  `code` int(11) NOT NULL AUTO_INCREMENT COMMENT '순번 (AUTO_INCREMENT)',
  `permission_key` varchar(100) NOT NULL COMMENT '권한 키 (예: user.view, ledger.edit)',
  `permission_name` varchar(100) NOT NULL COMMENT '권한 이름 (한글 표시용)',
  `description` varchar(255) DEFAULT NULL COMMENT '권한 설명',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '등록 시각',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '수정 시각',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '활성화 여부 (1=사용, 0=비활성)',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_code` (`code`) USING BTREE,
  UNIQUE KEY `uk_permission_key` (`permission_key`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='시스템 기능별 접근권한 정의 테이블 (UUID + 순번 구조)';


-- ----------------------------
-- Table structure for `auth_role_permissions`
-- ----------------------------
DROP TABLE IF EXISTS `auth_role_permissions`;
CREATE TABLE `auth_role_permissions` (
  `id` varchar(36) NOT NULL COMMENT 'UUID',
  `code` int(11) NOT NULL AUTO_INCREMENT COMMENT '순번 (AUTO_INCREMENT)',
  `role_id` varchar(36) NOT NULL COMMENT '역할 ID (auth_roles.id 참조)',
  `permission_id` varchar(36) NOT NULL COMMENT '권한 ID (auth_permissions.id 참조)',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '등록 시각',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_code` (`code`) USING BTREE,
  UNIQUE KEY `uk_role_permission` (`role_id`,`permission_id`) USING BTREE,
  KEY `idx_permission_id` (`permission_id`) USING BTREE,
  CONSTRAINT `fk_auth_role_permissions_permission` FOREIGN KEY (`permission_id`) REFERENCES `auth_permissions` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_auth_role_permissions_role` FOREIGN KEY (`role_id`) REFERENCES `auth_roles` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='역할별 권한 매핑 테이블 (UUID + 순번 구조)';


-- ----------------------------
-- Table structure for `auth_roles`
-- ----------------------------
DROP TABLE IF EXISTS `auth_roles`;
CREATE TABLE `auth_roles` (
  `id` varchar(36) NOT NULL COMMENT '역할 고유 ID (UUID)',
  `code` int(11) NOT NULL AUTO_INCREMENT COMMENT '순번 (AUTO_INCREMENT)',
  `role_key` varchar(50) NOT NULL COMMENT '역할 키값 (예: admin, manager, staff)',
  `role_name` varchar(100) NOT NULL COMMENT '역할 이름 (예: 관리자, 부서장, 일반직원)',
  `description` varchar(255) DEFAULT NULL COMMENT '역할 설명',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '활성화 여부 (1=활성, 0=비활성)',
  `created_by` varchar(36) DEFAULT NULL COMMENT '생성자 ID (auth_users.id 참조)',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '생성일시',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_code` (`code`),
  UNIQUE KEY `uk_role_key` (`role_key`),
  KEY `fk_auth_roles_created_by` (`created_by`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='시스템 역할(Role) 정의 테이블 (UUID + 순번 구조)';


-- ----------------------------
-- Table structure for `auth_sessions`
-- ----------------------------
DROP TABLE IF EXISTS `auth_sessions`;
CREATE TABLE `auth_sessions` (
  `id` varchar(36) NOT NULL COMMENT '세션 고유 ID (UUID)',
  `code` int(11) NOT NULL AUTO_INCREMENT COMMENT '순번 (AUTO_INCREMENT)',
  `user_id` varchar(36) NOT NULL COMMENT '사용자 ID (auth_users.id 참조)',
  `session_token` varchar(255) NOT NULL COMMENT '세션 토큰 (JWT 또는 해시)',
  `ip_address` varchar(45) DEFAULT NULL COMMENT '로그인 IP (IPv4/IPv6)',
  `user_agent` varchar(255) DEFAULT NULL COMMENT '브라우저/기기 정보',
  `login_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '로그인 시각',
  `last_activity` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '마지막 활동 시각',
  `logout_time` datetime DEFAULT NULL COMMENT '로그아웃 시각',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '세션 활성 여부 (1=활성, 0=만료)',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_code` (`code`) USING BTREE,
  UNIQUE KEY `uk_session_token` (`session_token`(191)) USING BTREE,
  KEY `idx_user_id` (`user_id`) USING BTREE,
  CONSTRAINT `fk_auth_sessions_user` FOREIGN KEY (`user_id`) REFERENCES `auth_users` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='사용자 세션 관리 테이블 (UUID + 순번 구조)';


-- ----------------------------
-- Table structure for `auth_user_roles`
-- ----------------------------
DROP TABLE IF EXISTS `auth_user_roles`;
CREATE TABLE `auth_user_roles` (
  `id` varchar(36) NOT NULL COMMENT 'UUID',
  `code` int(11) NOT NULL AUTO_INCREMENT COMMENT '순번 (AUTO_INCREMENT)',
  `user_id` varchar(36) NOT NULL COMMENT '사용자 ID (auth_users.id 참조)',
  `role_id` varchar(36) NOT NULL COMMENT '역할 ID (auth_roles.id 참조)',
  `assigned_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '역할 부여 시각',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '활성 여부 (1=활성, 0=해제)',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_code` (`code`) USING BTREE,
  UNIQUE KEY `uk_user_role` (`user_id`,`role_id`) USING BTREE,
  KEY `idx_role_id` (`role_id`) USING BTREE,
  CONSTRAINT `fk_auth_user_roles_role` FOREIGN KEY (`role_id`) REFERENCES `auth_roles` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_auth_user_roles_user` FOREIGN KEY (`user_id`) REFERENCES `auth_users` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='사용자 ↔ 역할 매핑 테이블 (UUID + 순번 구조)';


-- ----------------------------
-- Table structure for `auth_users`
-- ----------------------------
DROP TABLE IF EXISTS `auth_users`;
CREATE TABLE `auth_users` (
  `id` varchar(36) NOT NULL COMMENT 'UUID',
  `code` int(11) NOT NULL AUTO_INCREMENT COMMENT '코드 (AUTO_INCREMENT)',
  `username` varchar(50) NOT NULL COMMENT '로그인 ID',
  `password` varchar(255) NOT NULL COMMENT '비밀번호 (해시)',
  `email` varchar(100) DEFAULT NULL COMMENT '이메일',
  `two_factor_enabled` tinyint(1) DEFAULT '0' COMMENT '2단계 인증 여부',
  `active` tinyint(1) DEFAULT '1' COMMENT '활성 계정 여부',
  `approved` tinyint(1) DEFAULT '0' COMMENT '승인 여부 (관리자 승인)',
  `role` varchar(50) DEFAULT 'user' COMMENT '기본 역할 (예: admin, user)',
  `login_fail_count` int(11) DEFAULT '0' COMMENT '로그인 실패 횟수',
  `account_locked_until` datetime DEFAULT NULL COMMENT '계정 잠금 만료일시',
  `login_token` varchar(36) DEFAULT NULL COMMENT 'Remember Me 토큰',
  `last_login` datetime DEFAULT NULL COMMENT '마지막 로그인 일시',
  `last_login_ip` varchar(45) DEFAULT NULL COMMENT '마지막 로그인 IP',
  `last_login_device` varchar(100) DEFAULT NULL COMMENT '마지막 로그인 디바이스',
  `password_updated_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '비밀번호 변경일',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '가입일시',
  `created_by` varchar(36) DEFAULT NULL COMMENT '생성자 ID',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  `updated_by` varchar(36) DEFAULT NULL COMMENT '수정자 ID',
  `deleted_at` datetime DEFAULT NULL COMMENT '비활성화 계정 관리용',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_username` (`username`),
  UNIQUE KEY `uk_code` (`code`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='사용자 로그인/인증 계정 테이블 (Auth Core)';


-- ----------------------------
-- Table structure for `dashboard_calendar_event_teams`
-- ----------------------------
DROP TABLE IF EXISTS `dashboard_calendar_event_teams`;
CREATE TABLE `dashboard_calendar_event_teams` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'ID(식별자)',
  `event_id` int(11) NOT NULL COMMENT '이벤트 ID(외래키)',
  `team_name` varchar(100) CHARACTER SET utf8mb4 NOT NULL COMMENT '팀명',
  `team_manager` varchar(50) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '팀장 이름',
  `manager_phone` varchar(30) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '팀장 연락처',
  `members_name` varchar(100) CHARACTER SET utf8mb4 NOT NULL COMMENT '팀원 이름 목록(쉼표/JSON)',
  `description` text CHARACTER SET utf8mb4 COMMENT '비고/설명',
  PRIMARY KEY (`id`),
  KEY `event_id` (`event_id`),
  CONSTRAINT `dashboard_calendar_event_teams_ibfk_1` FOREIGN KEY (`event_id`) REFERENCES `dashboard_calendar_events` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=13 DEFAULT CHARSET=utf8 COMMENT='달력의 서브테이블(팀별)';

