-- ----------------------------
-- Table structure for `dashboard_calendar_events`
-- ----------------------------
DROP TABLE IF EXISTS `dashboard_calendar_events`;
CREATE TABLE `dashboard_calendar_events` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'ID(식별자)',
  `dept` varchar(50) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '부서',
  `date` date DEFAULT NULL COMMENT '날짜',
  `title` varchar(255) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '제목',
  `start` datetime DEFAULT NULL COMMENT '시작일시',
  `end` datetime DEFAULT NULL COMMENT '종료일시',
  `color` varchar(20) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '색상',
  `description` text CHARACTER SET utf8mb4 COMMENT '설명',
  `location` varchar(255) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '위치',
  `uid` varchar(100) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT 'UID(고유식별자)',
  `created` datetime DEFAULT NULL COMMENT '생성일시',
  `lastmodified` datetime DEFAULT NULL COMMENT '최종수정일시',
  `status` varchar(20) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '상태',
  `transp` varchar(20) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '시간차단여부/표시형식(TRANSP)',
  `rrule` varchar(255) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '반복규칙',
  `attendee` varchar(255) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '참석자',
  `organizer` varchar(255) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '주최자',
  `categories` varchar(255) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '카테고리',
  `priority` int(11) DEFAULT NULL COMMENT '우선순위',
  `sequence` int(11) DEFAULT NULL COMMENT '시퀀스(버젼 번호)',
  `url` varchar(255) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT 'URL',
  `class` varchar(20) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '공개범위(CLASS: Public/Private 등)',
  `dtstamp` datetime DEFAULT NULL COMMENT '타임스탬프(DTSTAMP)',
  `exdate` varchar(255) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '제외일(반복 제외 날짜)',
  `exrule` varchar(255) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '제외규칙(반복 제외 규칙)',
  `relatedto` varchar(255) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '연관ID(RELATED-TO)',
  `resources` varchar(255) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '자원(회의실/장비 등)',
  `comment` text CHARACTER SET utf8mb4 COMMENT '코멘트',
  `contact` varchar(255) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '연락처',
  `geo` varchar(50) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '좌표(위도/경도)',
  `attach` text CHARACTER SET utf8mb4 COMMENT '첨부(파일/링크)',
  `start_tz` varchar(50) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '시작 타임존',
  `end_tz` varchar(50) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '종료 타임존',
  `DTSTART` varchar(50) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '시작일시(DTSTART, iCalendar 표준)',
  `DTEND` varchar(50) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '종료일시(DTEND, iCalendar 표준)',
  `team_count` int(11) DEFAULT '0' COMMENT '팀 인원 수',
  `modifier` varchar(50) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '수정자',
  `modifydate` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  `is_completed` tinyint(1) DEFAULT '0' COMMENT '완료 여부',
  `manage_name_id` int(11) DEFAULT NULL COMMENT '관리명 ID(외래키)',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=719 DEFAULT CHARSET=utf8 COMMENT='일정/캘린더';

