-- Table structure for `home_about_coverimages`
-- ----------------------------
DROP TABLE IF EXISTS `home_about_coverimages`;
CREATE TABLE `home_about_coverimages` (
  `id` char(36) NOT NULL COMMENT '커버 이미지 고유 ID (UUID)',
  `code` int(11) NOT NULL AUTO_INCREMENT COMMENT '순번 (AUTO_INCREMENT)',
  `year` varchar(4) NOT NULL COMMENT '년도 (예: 2025)',
  `title` varchar(255) DEFAULT NULL COMMENT '타이틀',
  `alt` varchar(100) NOT NULL COMMENT '대체 텍스트 (이미지 설명)',
  `description` varchar(255) DEFAULT NULL COMMENT '설명',
  `src` varchar(255) NOT NULL COMMENT '이미지 경로 (/uploads/cover/...)',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '활성 상태 (1=노출, 0=비노출)',
  `sort_order` int(11) DEFAULT '0' COMMENT '정렬 순서 (작을수록 우선)',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_code` (`code`) USING BTREE,
  KEY `idx_year` (`year`) USING BTREE,
  KEY `idx_is_active` (`is_active`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='홈페이지 메인(로그인 전) 커버 이미지 관리 테이블 (UUID + 순번 구조)';


-- ----------------------------
-- Table structure for `ledger_account_subjects`
-- ----------------------------
DROP TABLE IF EXISTS `ledger_account_subjects`;
CREATE TABLE `ledger_account_subjects` (
  `id` char(36) NOT NULL COMMENT '고유 ID (UUID)',
  `code` int(11) NOT NULL AUTO_INCREMENT COMMENT '순번 (AUTO_INCREMENT)',
  `account_code` varchar(20) NOT NULL COMMENT '계정코드 (예: 101, 401 등)',
  `main_category` varchar(50) NOT NULL COMMENT '과목구분 (예: 자산, 부채, 자본, 수익, 비용)',
  `sub_category` varchar(50) NOT NULL COMMENT '과목분류 (예: 유동자산, 고정자산 등)',
  `account_type` varchar(50) NOT NULL COMMENT '계정구분 (예: 현금, 예금, 매출, 급여 등)',
  `account_class` varchar(50) DEFAULT NULL COMMENT '계정세분류 (상세한 분류)',
  `account_subject` varchar(100) NOT NULL COMMENT '계정과목명 (예: 현금, 외상매출금 등)',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '사용 여부 (1=사용, 0=비활성)',
  `note` varchar(255) DEFAULT NULL COMMENT '비고',
  `memo` text COMMENT '관리자 메모',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_code` (`code`) USING BTREE,
  UNIQUE KEY `uk_account_code` (`account_code`) USING BTREE,
  KEY `idx_main_category` (`main_category`) USING BTREE,
  KEY `idx_sub_category` (`sub_category`) USING BTREE,
  KEY `idx_is_active` (`is_active`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='회계 계정과목 마스터 테이블 (UUID + 순번 구조)';


-- ----------------------------
-- Table structure for `ledger_clients`
-- ----------------------------
DROP TABLE IF EXISTS `ledger_clients`;
CREATE TABLE `ledger_clients` (
  `id` varchar(36) NOT NULL COMMENT '거래처 고유 ID (UUID)',
  `code` int(11) NOT NULL AUTO_INCREMENT COMMENT '순번 (AUTO_INCREMENT)',
  `client_name` varchar(100) NOT NULL COMMENT '거래처명',
  `company_name` varchar(100) DEFAULT NULL COMMENT '상호',
  `registration_date` date DEFAULT NULL COMMENT '등록일자',
  `business_number` varchar(20) DEFAULT NULL COMMENT '사업자등록번호',
  `corporation_number` varchar(20) DEFAULT NULL COMMENT '법인번호 또는 주민등록번호',
  `business_type` varchar(50) DEFAULT NULL COMMENT '업태',
  `business_category` varchar(50) DEFAULT NULL COMMENT '업종',
  `business_status` varchar(20) DEFAULT NULL COMMENT '사업자등록 상태 (등록, 휴업, 폐업 등)',
  `business_certificate` varchar(255) DEFAULT NULL COMMENT '사업자등록증 파일 경로',
  `address` varchar(255) DEFAULT NULL COMMENT '주소',
  `address_detail` varchar(255) DEFAULT NULL COMMENT '상세주소',
  `phone` varchar(30) DEFAULT NULL COMMENT '전화번호',
  `fax` varchar(30) DEFAULT NULL COMMENT '팩스번호',
  `email` varchar(100) DEFAULT NULL COMMENT '이메일',
  `ceo_name` varchar(50) DEFAULT NULL COMMENT '대표자명',
  `ceo_phone` varchar(30) DEFAULT NULL COMMENT '대표자 연락처',
  `manager_name` varchar(50) DEFAULT NULL COMMENT '담당자명',
  `manager_phone` varchar(30) DEFAULT NULL COMMENT '담당자 연락처',
  `manufacture_number` varchar(50) DEFAULT NULL COMMENT '계좌번호',
  `item_category` varchar(100) DEFAULT NULL COMMENT '취급품목',
  `client_category` varchar(50) DEFAULT NULL COMMENT '거래처분류 (매입, 매출, 협력업체 등)',
  `client_grade` varchar(50) DEFAULT NULL COMMENT '거래처등급 (A, B, C 등)',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '활성상태 (1=활성, 0=비활성)',
  `note` varchar(255) DEFAULT NULL COMMENT '비고',
  `memo` text COMMENT '관리자 메모',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_code` (`code`) USING BTREE,
  KEY `idx_client_name` (`client_name`) USING BTREE,
  KEY `idx_business_number` (`business_number`) USING BTREE,
  KEY `idx_is_active` (`is_active`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='거래처 관리 테이블 (매입/매출/협력업체 등)';


-- ----------------------------
-- Table structure for `ledger_projects`
-- ----------------------------
DROP TABLE IF EXISTS `ledger_projects`;
CREATE TABLE `ledger_projects` (
  `id` varchar(36) NOT NULL COMMENT '프로젝트 고유 ID (UUID)',
  `code` int(11) NOT NULL AUTO_INCREMENT COMMENT '순번 (AUTO_INCREMENT)',
  `manage_name` varchar(100) DEFAULT NULL COMMENT '관리명 (내부 식별용 프로젝트명)',
  `client_id` varchar(36) DEFAULT NULL COMMENT '거래처 ID (ledger_clients.id FK)',
  `employee_id` varchar(36) DEFAULT NULL COMMENT '담당 직원 ID (user_profiles.id FK)',
  `site_agent` varchar(100) DEFAULT NULL COMMENT '현장대리인',
  `contract_type` varchar(50) DEFAULT NULL COMMENT '계약형태 (예: 도급, 하도급 등)',
  `director` varchar(50) DEFAULT NULL COMMENT '소장',
  `manager` varchar(50) DEFAULT NULL COMMENT '실장',
  `business_type` varchar(50) DEFAULT NULL COMMENT '업종',
  `housing_type` varchar(50) DEFAULT NULL COMMENT '주력분야',
  `construction_name` varchar(100) DEFAULT NULL COMMENT '공사명 (프로젝트 정식 명칭)',
  `site_region_city` varchar(50) DEFAULT NULL COMMENT '공사지역 (시도)',
  `site_region_district` varchar(50) DEFAULT NULL COMMENT '공사지역 (시군구)',
  `site_region_address` varchar(255) DEFAULT NULL COMMENT '공사지역 상세주소',
  `work_type` varchar(50) DEFAULT NULL COMMENT '공종 (예: 석공사, 토목공사 등)',
  `work_subtype` varchar(50) DEFAULT NULL COMMENT '공종 세분류',
  `work_detail_type` varchar(100) DEFAULT NULL COMMENT '세부 공사종류',
  `contract_work_type` varchar(50) DEFAULT NULL COMMENT '도급 종류 (직영, 하도 등)',
  `bid_type` varchar(50) DEFAULT NULL COMMENT '입찰형태 (지명, 경쟁, 수의 등)',
  `client_name` varchar(100) DEFAULT NULL COMMENT '발주자명',
  `client_type` varchar(50) DEFAULT NULL COMMENT '발주자 분류 (공공, 민간 등)',
  `permit_agency` varchar(100) DEFAULT NULL COMMENT '인허가기관',
  `permit_date` date DEFAULT NULL COMMENT '인허가일자',
  `contract_date` date DEFAULT NULL COMMENT '계약일자',
  `start_date` date DEFAULT NULL COMMENT '착공일자',
  `completion_date` date DEFAULT NULL COMMENT '준공일자',
  `bid_notice_date` date DEFAULT NULL COMMENT '입찰공고일',
  `initial_contract_amount` decimal(18,2) DEFAULT NULL COMMENT '최초 계약금액(공급가액)',
  `authorized_company_seal` varchar(100) DEFAULT NULL COMMENT '사용인감명',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '진행상태 (1=진행중, 0=완료/종료)',
  `note` varchar(255) DEFAULT NULL COMMENT '비고',
  `memo` text COMMENT '상세 메모',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_code` (`code`) USING BTREE,
  KEY `idx_manage_name` (`manage_name`) USING BTREE,
  KEY `idx_client_id` (`client_id`) USING BTREE,
  KEY `idx_employee_id` (`employee_id`) USING BTREE,
  KEY `idx_is_active` (`is_active`) USING BTREE,
  CONSTRAINT `fk_projects_client` FOREIGN KEY (`client_id`) REFERENCES `ledger_clients` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_projects_employee` FOREIGN KEY (`employee_id`) REFERENCES `user_profiles` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='프로젝트(현장/공사) 관리 테이블 (UUID + 순번 구조)';


-- ----------------------------
-- Table structure for `system_config`
-- ----------------------------
DROP TABLE IF EXISTS `system_config`;
CREATE TABLE `system_config` (
  `config_key` varchar(100) NOT NULL COMMENT '환경설정 키 (예: session_timeout, company_name)',
  `config_value` varchar(255) DEFAULT NULL COMMENT '환경설정 값',
  `category` varchar(50) DEFAULT NULL COMMENT '분류 (예: SYSTEM, AUTH, UI, EMAIL 등)',
  `description` varchar(255) DEFAULT NULL COMMENT '설명 (해당 설정의 의미)',
  `is_editable` tinyint(1) DEFAULT '1' COMMENT '수정 가능 여부 (1=관리자 수정 가능, 0=고정값)',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`config_key`) USING BTREE,
  KEY `idx_category` (`category`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='시스템 환경설정 / 세션관리 테이블 (Key-Value 구조)';


-- ----------------------------
-- Table structure for `user_activity_logs`
-- ----------------------------
DROP TABLE IF EXISTS `user_activity_logs`;
CREATE TABLE `user_activity_logs` (
  `id` varchar(36) NOT NULL COMMENT '로그 고유 ID (UUID)',
  `code` int(11) NOT NULL AUTO_INCREMENT COMMENT '순번 (AUTO_INCREMENT)',
  `user_id` varchar(36) DEFAULT NULL COMMENT '사용자 ID (auth_users.id 참조)',
  `session_id` varchar(36) DEFAULT NULL COMMENT '세션 ID (auth_sessions.id 참조)',
  `action_type` varchar(50) NOT NULL COMMENT '행동유형 (LOGIN, LOGOUT, CREATE, UPDATE, DELETE, APPROVE 등)',
  `target_table` varchar(100) DEFAULT NULL COMMENT '대상 테이블명',
  `target_id` varchar(36) DEFAULT NULL COMMENT '대상 데이터의 ID (예: 문서 ID, 게시물 ID 등)',
  `description` text COMMENT '상세 내용 (무엇을, 어떻게, 누가, 언제)',
  `ip_address` varchar(45) DEFAULT NULL COMMENT '사용자 IP 주소 (IPv4/IPv6)',
  `user_agent` varchar(255) DEFAULT NULL COMMENT '사용자 브라우저 / 디바이스 정보',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '로그 발생 시각',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_code` (`code`) USING BTREE,
  KEY `idx_user_id` (`user_id`) USING BTREE,
  KEY `idx_session_id` (`session_id`) USING BTREE,
  KEY `idx_action_type` (`action_type`) USING BTREE,
  CONSTRAINT `fk_user_activity_session` FOREIGN KEY (`session_id`) REFERENCES `auth_sessions` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_user_activity_user` FOREIGN KEY (`user_id`) REFERENCES `auth_users` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='사용자 활동 로그 테이블 (UUID + 순번 구조, 사용자·세션 연계)';


-- ----------------------------
-- Table structure for `user_approval_lines`
-- ----------------------------
DROP TABLE IF EXISTS `user_approval_lines`;
CREATE TABLE `user_approval_lines` (
  `id` varchar(36) NOT NULL COMMENT '결재라인 고유 ID (UUID)',
  `code` int(11) NOT NULL AUTO_INCREMENT COMMENT '순번 (AUTO_INCREMENT)',
  `user_id` varchar(36) NOT NULL COMMENT '기안자 ID (auth_users.id)',
  `approver_id` varchar(36) NOT NULL COMMENT '결재자 ID (auth_users.id)',
  `sequence` int(11) NOT NULL COMMENT '결재 순서 (1, 2, 3...)',
  `role_id` varchar(36) DEFAULT NULL COMMENT '결재자 역할 ID (auth_roles.id)',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '활성 상태 (1=활성, 0=비활성)',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '등록 시각',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_code` (`code`) USING BTREE,
  UNIQUE KEY `uk_user_sequence` (`user_id`,`sequence`) USING BTREE,
  KEY `idx_approver_id` (`approver_id`) USING BTREE,
  KEY `idx_role_id` (`role_id`) USING BTREE,
  CONSTRAINT `fk_approval_approver` FOREIGN KEY (`approver_id`) REFERENCES `auth_users` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_approval_role` FOREIGN KEY (`role_id`) REFERENCES `auth_roles` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_approval_user` FOREIGN KEY (`user_id`) REFERENCES `auth_users` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='결재라인 관리 테이블 (UUID + 순번 구조, 사용자·역할 연결)';


-- ----------------------------
-- Table structure for `user_certificates`
-- ----------------------------
DROP TABLE IF EXISTS `user_certificates`;
CREATE TABLE `user_certificates` (
  `id` varchar(36) NOT NULL COMMENT '자격증 고유 ID (UUID)',
  `code` int(11) NOT NULL AUTO_INCREMENT COMMENT '순번 (AUTO_INCREMENT)',
  `user_id` varchar(36) NOT NULL COMMENT '사용자 ID (auth_users.id 참조)',
  `certificate_name` varchar(100) NOT NULL COMMENT '자격증명 / 교육명',
  `certificate_number` varchar(100) DEFAULT NULL COMMENT '자격증 번호',
  `issued_by` varchar(100) DEFAULT NULL COMMENT '발급기관',
  `issue_date` date DEFAULT NULL COMMENT '발급일자',
  `expiry_date` date DEFAULT NULL COMMENT '만료일자',
  `certificate_type` varchar(50) DEFAULT NULL COMMENT '구분 (예: 자격증, 교육이수, 면허 등)',
  `attachment_path` varchar(255) DEFAULT NULL COMMENT '자격증 스캔본 파일 경로',
  `memo` text COMMENT '비고 / 메모',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '유효 여부 (1=유효, 0=만료/삭제)',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_code` (`code`) USING BTREE,
  KEY `idx_user_id` (`user_id`) USING BTREE,
  KEY `idx_certificate_name` (`certificate_name`) USING BTREE,
  KEY `idx_certificate_type` (`certificate_type`) USING BTREE,
  CONSTRAINT `fk_user_certificates_user` FOREIGN KEY (`user_id`) REFERENCES `auth_users` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='사용자 자격증 / 면허 / 교육이수 관리 테이블 (UUID + 순번 구조)';


-- ----------------------------
-- Table structure for `user_departments`
-- ----------------------------
DROP TABLE IF EXISTS `user_departments`;
CREATE TABLE `user_departments` (
  `id` varchar(36) NOT NULL COMMENT '부서 고유 ID (UUID)',
  `code` int(11) NOT NULL AUTO_INCREMENT COMMENT '순번 (AUTO_INCREMENT)',
  `parent_id` varchar(36) DEFAULT NULL COMMENT '상위 부서 ID (자체 참조)',
  `dept_code` varchar(20) DEFAULT NULL COMMENT '부서 코드 (예: HR001, ENG002 등)',
  `dept_name` varchar(100) NOT NULL COMMENT '부서명',
  `manager_id` varchar(36) DEFAULT NULL COMMENT '부서장 ID (auth_users.id 참조)',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '활성 상태 (1=활성, 0=비활성)',
  `sort_order` int(11) DEFAULT '0' COMMENT '표시 순서 (정렬용)',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_code` (`code`) USING BTREE,
  UNIQUE KEY `uk_dept_code` (`dept_code`) USING BTREE,
  KEY `idx_parent_id` (`parent_id`) USING BTREE,
  KEY `idx_manager_id` (`manager_id`) USING BTREE,
  CONSTRAINT `fk_user_departments_manager` FOREIGN KEY (`manager_id`) REFERENCES `auth_users` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_user_departments_parent` FOREIGN KEY (`parent_id`) REFERENCES `user_departments` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='조직(부서) 관리 테이블 (UUID + 순번 구조, 자체 참조 계층형 구조)';


-- ----------------------------
-- Table structure for `user_positions`
-- ----------------------------
DROP TABLE IF EXISTS `user_positions`;
CREATE TABLE `user_positions` (
  `id` varchar(36) NOT NULL COMMENT '직위 고유 ID (UUID)',
  `code` int(11) NOT NULL AUTO_INCREMENT COMMENT '순번 (AUTO_INCREMENT)',
  `position_code` varchar(20) DEFAULT NULL COMMENT '직위 코드 (예: CEO, DIR, MGR, STAF 등)',
  `position_name` varchar(50) NOT NULL COMMENT '직위명 (예: 대표이사, 이사, 부장, 차장, 과장, 대리, 사원)',
  `level_rank` int(11) DEFAULT '0' COMMENT '직위 등급 (숫자가 작을수록 상위)',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '활성 상태 (1=활성, 0=비활성)',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_code` (`code`) USING BTREE,
  UNIQUE KEY `uk_position_code` (`position_code`) USING BTREE,
  KEY `idx_level_rank` (`level_rank`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='직위 / 직책 관리 테이블 (UUID + 순번 구조)';


-- ----------------------------
-- Table structure for `user_profiles`
-- ----------------------------
DROP TABLE IF EXISTS `user_profiles`;
CREATE TABLE `user_profiles` (
  `id` varchar(36) NOT NULL COMMENT '프로필 고유 ID (UUID)',
  `code` int(11) NOT NULL AUTO_INCREMENT COMMENT '순번 (AUTO_INCREMENT)',
  `user_id` varchar(36) NOT NULL COMMENT '사용자 ID (auth_users.id FK)',
  `employee_name` varchar(50) NOT NULL COMMENT '직원 이름',
  `phone` varchar(20) DEFAULT NULL COMMENT '연락처',
  `address` varchar(255) DEFAULT NULL COMMENT '주소',
  `address_detail` varchar(255) DEFAULT NULL COMMENT '상세주소',
  `department_id` varchar(36) DEFAULT NULL COMMENT '부서 ID (user_departments.id FK)',
  `position_id` varchar(36) DEFAULT NULL COMMENT '직위 ID (user_positions.id FK)',
  `doc_hire_date` date DEFAULT NULL COMMENT '문서상 입사일',
  `real_hire_date` date DEFAULT NULL COMMENT '실제 입사일',
  `doc_retire_date` date DEFAULT NULL COMMENT '문서상 퇴사일',
  `real_retire_date` date DEFAULT NULL COMMENT '실제 퇴사일',
  `rrn` varchar(20) DEFAULT NULL COMMENT '주민등록번호 (암호화 저장)',
  `emergency_phone` varchar(20) DEFAULT NULL COMMENT '비상연락처',
  `client_id` varchar(36) DEFAULT NULL COMMENT '거래처 ID (외부 협력업체 연동용)',
  `note` varchar(255) DEFAULT NULL COMMENT '비고',
  `memo` text COMMENT '관리자 메모',
  `profile_image` varchar(255) DEFAULT NULL COMMENT '프로필 사진 경로',
  `certificate_name` varchar(50) DEFAULT NULL COMMENT '대표 자격증 이름',
  `certificate_file` varchar(255) DEFAULT NULL COMMENT '대표 자격증 파일 경로',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '재직 여부 (1=재직, 0=퇴사)',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  `deleted_at` datetime DEFAULT NULL COMMENT '삭제일시 (소프트 삭제용)',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_code` (`code`) USING BTREE,
  KEY `idx_user_id` (`user_id`) USING BTREE,
  KEY `idx_department_id` (`department_id`) USING BTREE,
  KEY `idx_position_id` (`position_id`) USING BTREE,
  CONSTRAINT `fk_user_profiles_department` FOREIGN KEY (`department_id`) REFERENCES `user_departments` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_user_profiles_position` FOREIGN KEY (`position_id`) REFERENCES `user_positions` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_user_profiles_user` FOREIGN KEY (`user_id`) REFERENCES `auth_users` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='직원 인사 / 프로필 관리 테이블 (UUID + 순번 구조, 부서/직위 FK 연동)';

SET FOREIGN_KEY_CHECKS=1;
